SELECT "t3"."I_ITEM_DESC00" AS "I_ITEM_DESC", "t3"."W_WAREHOUSE_NAME00" AS "W_WAREHOUSE_NAME", "t3"."D_WEEK_SEQ20" AS "D_WEEK_SEQ", "t3"."$f30" AS "NO_PROMO", "t3"."$f31" AS "PROMO", "t3"."$f32" AS "TOTAL_CNT"
FROM (SELECT "ITEM"."I_ITEM_DESC" AS "I_ITEM_DESC00", "WAREHOUSE"."W_WAREHOUSE_NAME" AS "W_WAREHOUSE_NAME00", "DATE_DIM"."D_WEEK_SEQ" AS "D_WEEK_SEQ20", COUNT(*) AS "$f30", COUNT(*) AS "$f31", COUNT(*) AS "$f32"
FROM "tpcds"."CATALOG_SALES"
INNER JOIN "tpcds"."INVENTORY" ON "CATALOG_SALES"."CS_ITEM_SK" = "INVENTORY"."INV_ITEM_SK"
INNER JOIN "tpcds"."WAREHOUSE" ON "INVENTORY"."INV_WAREHOUSE_SK" = "WAREHOUSE"."W_WAREHOUSE_SK"
INNER JOIN "tpcds"."ITEM" ON "CATALOG_SALES"."CS_ITEM_SK" = "ITEM"."I_ITEM_SK"
INNER JOIN "tpcds"."CUSTOMER_DEMOGRAPHICS" ON "CATALOG_SALES"."CS_BILL_CDEMO_SK" = "CUSTOMER_DEMOGRAPHICS"."CD_DEMO_SK"
INNER JOIN "tpcds"."HOUSEHOLD_DEMOGRAPHICS" ON "CATALOG_SALES"."CS_BILL_HDEMO_SK" = "HOUSEHOLD_DEMOGRAPHICS"."HD_DEMO_SK"
INNER JOIN "tpcds"."DATE_DIM" ON "CATALOG_SALES"."CS_SOLD_DATE_SK" = "DATE_DIM"."D_DATE_SK"
INNER JOIN "tpcds"."DATE_DIM" AS "DATE_DIM0" ON "INVENTORY"."INV_DATE_SK" = "DATE_DIM0"."D_DATE_SK"
INNER JOIN "tpcds"."DATE_DIM" AS "DATE_DIM1" ON "CATALOG_SALES"."CS_SHIP_DATE_SK" = "DATE_DIM1"."D_DATE_SK"
LEFT JOIN "tpcds"."PROMOTION" ON "CATALOG_SALES"."CS_PROMO_SK" = "PROMOTION"."P_PROMO_SK"
LEFT JOIN "tpcds"."CATALOG_RETURNS" ON "CATALOG_SALES"."CS_ITEM_SK" = "CATALOG_RETURNS"."CR_ITEM_SK" AND "CATALOG_SALES"."CS_ORDER_NUMBER" = "CATALOG_RETURNS"."CR_ORDER_NUMBER"
WHERE "DATE_DIM"."D_WEEK_SEQ" = "DATE_DIM0"."D_WEEK_SEQ" AND ("INVENTORY"."INV_QUANTITY_ON_HAND" < "CATALOG_SALES"."CS_QUANTITY" AND "DATE_DIM1"."D_DATE" > ("DATE_DIM"."D_DATE" + INTERVAL '5 days')) AND ("HOUSEHOLD_DEMOGRAPHICS"."HD_BUY_POTENTIAL" = '1001-5000' AND ("DATE_DIM"."D_YEAR" = 1998 AND "CUSTOMER_DEMOGRAPHICS"."CD_MARITAL_STATUS" = 'D'))
GROUP BY "ITEM"."I_ITEM_DESC", "WAREHOUSE"."W_WAREHOUSE_NAME", "DATE_DIM"."D_WEEK_SEQ"
ORDER BY 6 DESC, "ITEM"."I_ITEM_DESC", "WAREHOUSE"."W_WAREHOUSE_NAME", "DATE_DIM"."D_WEEK_SEQ"
FETCH NEXT 100 ROWS ONLY) AS "t3"
